// 入力待ちループの代表例
import java.util.Scanner;

Scanner sc = new Scanner(System.in);
// 条件が成り立つ間、繰り返す
while (true) {
    System.out.print("コマンドを入力（quitで終了）: ");
    // 変数の宣言と初期化
    String cmd = sc.nextLine();
    // 条件分岐
    if (cmd.equals("quit")) {
        break; // ループを抜ける
    }
    System.out.println("実行: " + cmd);
}
System.out.println("終了しました");

