// for: 1から5まで表示（回数が明確）
for (int i = 1; i <= 5; i++) {
    System.out.println(i);
}

// while: 条件を満たすまで（回数不明）
int num = 1;
while (num < 1000) {
    num *= 2; // 2倍ずつ増やす
}
System.out.println(num); // 1024

// do-while: メニュー表示（必ず1回表示）
int choice;
do {
    System.out.println("1:開始 2:設定 0:終了");
    choice = 1; // 仮の値
} while (choice != 0);

// break: ループを即座に抜ける
for (int i = 0; i < 10; i++) {
    if (i == 5) break;
    System.out.print(i + " ");
}
// 出力: 0 1 2 3 4

// continue: 今回のループをスキップして次の回へ
for (int i = 0; i < 5; i++) {
    if (i == 2) continue;
    System.out.print(i + " ");
}
// 出力: 0 1 3 4

// ラベル付きbreak: 外側のループごと抜ける
outer:
for (int i = 0; i < 3; i++) {
    for (int j = 0; j < 3; j++) {
        if (i == 1 && j == 1) {
            break outer; // 外側ループごと脱出！
        }
        System.out.print("(" + i + "," + j + ") ");
    }
}
// 出力: (0,0) (0,1) (0,2) (1,0)
// → (1,1)でouter全体を抜けた

System.out.println();

// ラベル付きcontinue: 外側ループの次の回へ
outer:
for (int i = 0; i < 3; i++) {
    for (int j = 0; j < 3; j++) {
        if (j == 1) {
            continue outer; // 外側ループの次の回へ！
        }
        System.out.print("(" + i + "," + j + ") ");
    }
}
// 出力: (0,0) (1,0) (2,0)
// → j==1で外側のiの次の回に進むため、j=1,2はスキップ

// ラベルなしのbreakは最も内側のループだけ抜ける
for (int i = 0; i < 3; i++) {
    for (int j = 0; j < 3; j++) {
        if (j == 1) break; // 内側のjループだけ抜ける
        System.out.print("(" + i + "," + j + ") ");
    }
}
// 出力: (0,0) (1,0) (2,0)

